import type {
    InventoryConfig,
    RarityData,
    RawItemId,
    ResolveTooltipItemOptions,
    TooltipItem,
} from './types';

export const DEFAULT_ASSET_BASE_URL =
    'https://raw.githubusercontent.com/BZ-Developer-Team/bz-axie-assets/refs/heads/main';

const DEFAULT_RARITY = 'common';

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/, '');

const getAssetUrl = (baseUrl: string, directory: string, fileName: string): string => {
    const base = trimTrailingSlash(baseUrl);
    const directoryBase = base.endsWith(`/${directory}`) ? base : `${base}/${directory}`;
    return `${directoryBase}/${encodeURIComponent(fileName)}.webp`;
};

export const parseRawItemId = (
    rawItemId: RawItemId,
): { itemId: string; itemUuid?: string } => {
    if (!rawItemId) return { itemId: '', itemUuid: undefined };
    const [itemId, itemUuid] = rawItemId.split('*');
    return { itemId, itemUuid };
};

export const getImageUrl = (
    rawItemId: RawItemId,
    assetBaseUrl = DEFAULT_ASSET_BASE_URL,
): string => getAssetUrl(assetBaseUrl, 'items', parseRawItemId(rawItemId).itemId);

export const getRarityImageUrl = (
    name: string,
    assetBaseUrl = DEFAULT_ASSET_BASE_URL,
): string => getAssetUrl(assetBaseUrl, 'item_bg_rarity', name);

export const getTooltipImageUrl = (
    name: string,
    assetBaseUrl = DEFAULT_ASSET_BASE_URL,
): string => getAssetUrl(assetBaseUrl, 'item_bg_tooltip', name);

export const rgbToCss = (rgb?: number[]): string | undefined => {
    if (!rgb || rgb.length < 3) return undefined;
    const [r, g, b] = rgb;
    return `rgb(${r}, ${g}, ${b})`;
};

export const getRarityName = (
    rawItemId: RawItemId,
    config?: InventoryConfig,
): string => {
    const itemName = parseRawItemId(rawItemId).itemId;
    return config?.ItemRarity?.[itemName] || DEFAULT_RARITY;
};

export const getRarityData = (
    rawItemId: RawItemId,
    config?: InventoryConfig,
): RarityData | null => {
    const rarityName = getRarityName(rawItemId, config);
    return config?.Rarity?.[rarityName] ?? config?.Rarity?.[DEFAULT_RARITY] ?? null;
};

export const getRarityLabelColor = (
    rawItemId: RawItemId,
    config?: InventoryConfig,
): string | undefined => rgbToCss(getRarityData(rawItemId, config)?.label);

export const getRarityHoverColor = (
    rawItemId: RawItemId,
    config?: InventoryConfig,
): string | undefined => rgbToCss(getRarityData(rawItemId, config)?.hover);

export const getItemCategory = (
    rawItemId: RawItemId,
    config?: InventoryConfig,
): string | undefined => {
    const itemId = parseRawItemId(rawItemId).itemId;
    const category = config?.Category;
    if (!category?.Menu || !category.Items) return undefined;

    for (const menu of category.Menu) {
        if (menu.Id === 'All') continue;
        if ((category.Items[menu.Id] || []).includes(itemId)) return menu.Name;
    }
    return undefined;
};

export const resolveTooltipItem = (
    rawItemId: RawItemId,
    options: ResolveTooltipItemOptions = {},
): TooltipItem => {
    const itemId = parseRawItemId(rawItemId).itemId;
    const config = options.config;
    const item = options.item;
    const itemConfig = options.itemConfig;
    const rarity = getRarityData(rawItemId, config);
    const assetBaseUrl = options.assetBaseUrl || config?.Image?.CDN || DEFAULT_ASSET_BASE_URL;
    const overrides = options.overrides || {};

    return {
        rawItemId,
        label: overrides.label ?? itemConfig?.label ?? rawItemId,
        imageUrl: overrides.imageUrl ?? getImageUrl(rawItemId, assetBaseUrl),
        count: overrides.count ?? item?.count ?? itemConfig?.count ?? 0,
        limit: overrides.limit ?? itemConfig?.limit,
        weight: overrides.weight ?? itemConfig?.weight,
        category: overrides.category ?? getItemCategory(itemId, config),
        description:
            overrides.description
            ?? config?.Description?.[itemId]
            ?? config?.Description?.Default,
        labelColor: overrides.labelColor ?? rgbToCss(rarity?.label),
        backgroundUrl: overrides.backgroundUrl ?? rarity?.tooltip_bg,
        metadata: overrides.metadata ?? item?.metadata ?? itemConfig?.metadata,
    };
};

